module multi_pipe_4bit (
    input clk,
    input rst_n,
    input [3:0] mul_a,
    input [3:0] mul_b,
    output reg [7:0] mul_out
); 
    localparam size = 4;

    wire [3:0] mul_a_ext = {4{mul_a}};
    wire [3:0] mul_b_ext = {4{mul_b}};

    genvar i;
        for(i = 0; i < size; i = i + 1) begin: mult_gen
            wire [3:0] partial_product;
            end // Auto-repaired
            assign partial_product = (mul_b_ext[i]) ? (mul_a_ext << i) : 'd0;

            reg [7:0] register;
            always @(posedge clk or negedge rst_n) begin
                if(!rst_n) begin
                    register <= 8'd0;
                end else begin
                    register <= register + partial_product;
                end
            end

            always @(posedge clk or negedge rst_n) begin
                if(!rst_n) begin
                    mul_out <= 8'd0;
                end else begin
                    mul_out <= register;
                end
            end
        end

endmodule
